from __future__ import annotations

import os
import io
import json
import sqlite3
import threading
import pickle
from datetime import datetime
from typing import List, Optional, Dict, Any

import numpy as np
from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field
from PIL import Image
from sklearn.pipeline import Pipeline
from sklearn.preprocessing import StandardScaler
from sklearn.linear_model import LogisticRegression

DB_PATH = os.getenv("LABELING_DB_PATH", "labeling.db")
MODEL_PATH = os.getenv("LABELING_MODEL_PATH", "trained_model.pkl")

app = FastAPI(title="Crowdsourced Data Labeling System")
db_lock = threading.Lock()


def get_conn():
    conn = sqlite3.connect(DB_PATH, check_same_thread=False)
    conn.row_factory = sqlite3.Row
    return conn


def init_db():
    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS images (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                external_id TEXT UNIQUE,
                image_bytes BLOB NOT NULL,
                created_at TEXT NOT NULL
            )
            """
        )
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS annotations (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                image_id INTEGER NOT NULL,
                annotator_id TEXT NOT NULL,
                label TEXT NOT NULL,
                created_at TEXT NOT NULL,
                UNIQUE(image_id, annotator_id),
                FOREIGN KEY(image_id) REFERENCES images(id)
            )
            """
        )
        conn.commit()
        conn.close()


@app.on_event("startup")
def startup():
    init_db()


class ImageCreateRequest(BaseModel):
    external_id: str = Field(..., description="Unique image identifier")
    image_base64: str = Field(..., description="Base64-encoded image bytes")


class AnnotationRequest(BaseModel):
    annotator_id: str
    label: str


class TrainResponse(BaseModel):
    trained_samples: int
    classes: List[str]
    model_path: str


def decode_base64_image(data: str) -> bytes:
    import base64
    try:
        return base64.b64decode(data)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid base64 image data")


def load_image_features(image_bytes: bytes) -> np.ndarray:
    try:
        img = Image.open(io.BytesIO(image_bytes)).convert("RGB").resize((64, 64))
        arr = np.asarray(img, dtype=np.float32) / 255.0
        feat = arr.reshape(-1)
        return feat
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image content")


def get_image_by_external_id(external_id: str) -> Optional[sqlite3.Row]:
    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute("SELECT * FROM images WHERE external_id = ?", (external_id,))
        row = cur.fetchone()
        conn.close()
        return row


def get_image_by_id(image_id: int) -> Optional[sqlite3.Row]:
    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute("SELECT * FROM images WHERE id = ?", (image_id,))
        row = cur.fetchone()
        conn.close()
        return row


def majority_vote(labels: List[str]) -> Optional[str]:
    if not labels:
        return None
    counts: Dict[str, int] = {}
    for label in labels:
        counts[label] = counts.get(label, 0) + 1
    max_count = max(counts.values())
    winners = sorted([label for label, count in counts.items() if count == max_count])
    return winners[0]


@app.post("/images")
def create_image(req: ImageCreateRequest):
    image_bytes = decode_base64_image(req.image_base64)
    _ = load_image_features(image_bytes)
    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        try:
            cur.execute(
                "INSERT INTO images (external_id, image_bytes, created_at) VALUES (?, ?, ?)",
                (req.external_id, image_bytes, datetime.utcnow().isoformat()),
            )
            conn.commit()
        except sqlite3.IntegrityError:
            conn.close()
            raise HTTPException(status_code=409, detail="external_id already exists")
        image_id = cur.lastrowid
        conn.close()
    return {"id": image_id, "external_id": req.external_id}


@app.post("/images/{external_id}/annotations")
def submit_annotation(external_id: str, req: AnnotationRequest):
    image = get_image_by_external_id(external_id)
    if not image:
        raise HTTPException(status_code=404, detail="Image not found")
    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        try:
            cur.execute(
                """
                INSERT INTO annotations (image_id, annotator_id, label, created_at)
                VALUES (?, ?, ?, ?)
                ON CONFLICT(image_id, annotator_id) DO UPDATE SET
                    label=excluded.label,
                    created_at=excluded.created_at
                """,
                (image["id"], req.annotator_id, req.label, datetime.utcnow().isoformat()),
            )
            conn.commit()
        finally:
            conn.close()
    return {
        "image_id": image["id"],
        "external_id": external_id,
        "annotator_id": req.annotator_id,
        "label": req.label,
    }


@app.get("/images/{external_id}/annotations")
def list_annotations(external_id: str):
    image = get_image_by_external_id(external_id)
    if not image:
        raise HTTPException(status_code=404, detail="Image not found")
    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute(
            "SELECT annotator_id, label, created_at FROM annotations WHERE image_id = ? ORDER BY created_at ASC",
            (image["id"],),
        )
        rows = cur.fetchall()
        conn.close()
    return {
        "external_id": external_id,
        "annotations": [
            {
                "annotator_id": row["annotator_id"],
                "label": row["label"],
                "created_at": row["created_at"],
            }
            for row in rows
        ],
    }


@app.get("/images/{external_id}/aggregate")
def aggregate_image_labels(external_id: str):
    image = get_image_by_external_id(external_id)
    if not image:
        raise HTTPException(status_code=404, detail="Image not found")
    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute("SELECT label FROM annotations WHERE image_id = ?", (image["id"],))
        rows = cur.fetchall()
        conn.close()
    labels = [row["label"] for row in rows]
    aggregated = majority_vote(labels)
    return {
        "external_id": external_id,
        "num_annotations": len(labels),
        "aggregated_label": aggregated,
    }


@app.get("/dataset/aggregated")
def get_aggregated_dataset():
    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute("SELECT id, external_id FROM images ORDER BY id ASC")
        images = cur.fetchall()
        result = []
        for image in images:
            cur.execute("SELECT label FROM annotations WHERE image_id = ?", (image["id"],))
            labels = [row["label"] for row in cur.fetchall()]
            result.append(
                {
                    "image_id": image["id"],
                    "external_id": image["external_id"],
                    "num_annotations": len(labels),
                    "aggregated_label": majority_vote(labels),
                }
            )
        conn.close()
    return {"items": result}


@app.post("/train", response_model=TrainResponse)
def train_model():
    with db_lock:
        conn = get_conn()
        cur = conn.cursor()
        cur.execute("SELECT id, image_bytes FROM images ORDER BY id ASC")
        images = cur.fetchall()

        X = []
        y = []

        for image in images:
            cur.execute("SELECT label FROM annotations WHERE image_id = ?", (image["id"],))
            labels = [row["label"] for row in cur.fetchall()]
            agg = majority_vote(labels)
            if agg is None:
                continue
            feat = load_image_features(image["image_bytes"])
            X.append(feat)
            y.append(agg)

        conn.close()

    if len(X) < 2:
        raise HTTPException(status_code=400, detail="Need at least 2 labeled images to train")

    X_arr = np.vstack(X)
    y_arr = np.array(y)

    model = Pipeline(
        steps=[
            ("scaler", StandardScaler()),
            ("clf", LogisticRegression(max_iter=1000)),
        ]
    )
    model.fit(X_arr, y_arr)

    with open(MODEL_PATH, "wb") as f:
        pickle.dump(model, f)

    return TrainResponse(
        trained_samples=len(y),
        classes=sorted(list(set(y))),
        model_path=MODEL_PATH,
    )


@app.post("/predict/{external_id}")
def predict_image(external_id: str):
    image = get_image_by_external_id(external_id)
    if not image:
        raise HTTPException(status_code=404, detail="Image not found")
    if not os.path.exists(MODEL_PATH):
        raise HTTPException(status_code=400, detail="Model not trained")

    with open(MODEL_PATH, "rb") as f:
        model = pickle.load(f)

    feat = load_image_features(image["image_bytes"]).reshape(1, -1)
    pred = model.predict(feat)[0]

    response: Dict[str, Any] = {"external_id": external_id, "predicted_label": str(pred)}
    if hasattr(model, "predict_proba"):
        probs = model.predict_proba(feat)[0]
        classes = [str(c) for c in model.classes_]
        response["probabilities"] = {classes[i]: float(probs[i]) for i in range(len(classes))}
    return response


@app.get("/health")
def health():
    return {"status": "ok"}